export component OverviewTab inherits Rectangle {
    VerticalLayout {
        padding: 24px;
        spacing: 16px;
        alignment: center;

        Text {
            text: "Overview";
            font-size: 18px;
            font-weight: 600;
            horizontal-alignment: center;
        }

        Text {
            text: "Overview behavior is reserved for a later port phase.";
            font-size: 14px;
            horizontal-alignment: center;
        }
    }
}

import { TabWidget } from "std-widgets.slint";
import { OverviewTab } from "overview_tab.slint";
import { F4seTab } from "f4se_tab.slint";
import { ScannerTab } from "scanner_tab.slint";
import { ToolsTab } from "tools_tab.slint";
import { SettingsTab } from "settings_tab.slint";
import { AboutTab } from "about_tab.slint";

export component MainWindow inherits Window {
    in-out property <string> update-source: "nexus";
    in-out property <string> log-level: "info";
    callback update-source-selected(string);
    callback log-level-selected(string);

    title: "Collective Modding Toolkit";
    width: 900px;
    height: 640px;

    // The tab labels and order mirror CMT/src/cm_checker.py and CMT/src/enums.py.
    TabWidget {
        Tab {
            title: "Overview";
            OverviewTab {}
        }

        Tab {
            title: "F4SE";
            F4seTab {}
        }

        Tab {
            title: "Scanner";
            ScannerTab {}
        }

        Tab {
            title: "Tools";
            ToolsTab {}
        }

        Tab {
            title: "Settings";
            SettingsTab {
                update-source <=> root.update-source;
                log-level <=> root.log-level;
                update-source-selected(value) => {
                    root.update-source-selected(value);
                }
                log-level-selected(value) => {
                    root.log-level-selected(value);
                }
            }
        }

        Tab {
            title: "About";
            AboutTab {}
        }
    }
}

import { GroupBox } from "std-widgets.slint";

component SettingsRadioOption inherits Rectangle {
    in property <string> text;
    in property <bool> checked;
    callback selected();

    height: 24px;
    min-width: 180px;

    HorizontalLayout {
        spacing: 8px;
        alignment: start;

        Rectangle {
            width: 14px;
            height: 14px;
            border-radius: 7px;
            border-width: 1px;
            border-color: root.checked ? #4da3ff : #9a9a9a;

            Rectangle {
                width: 8px;
                height: 8px;
                x: 3px;
                y: 3px;
                border-radius: 4px;
                background: root.checked ? #4da3ff : transparent;
            }
        }

        Text {
            text: root.text;
            font-size: 14px;
            color: #f3f3f3;
            vertical-alignment: center;
        }
    }

    TouchArea {
        clicked => {
            root.selected();
        }
    }
}

export component SettingsTab inherits Rectangle {
    in-out property <string> update-source: "nexus";
    in-out property <string> log-level: "info";
    callback update-source-selected(string);
    callback log-level-selected(string);

    background: #202020;

    VerticalLayout {
        padding: 24px;
        spacing: 16px;
        alignment: start;

        HorizontalLayout {
            spacing: 16px;
            alignment: start;

            GroupBox {
                title: "Update Channel";

                VerticalLayout {
                    padding: 8px;
                    spacing: 8px;
                    alignment: start;

                    SettingsRadioOption {
                        text: "All: GitHub & Nexus Mods";
                        checked: root.update-source == "both";
                        selected => {
                            root.update-source = "both";
                            root.update-source-selected("both");
                        }
                    }

                    SettingsRadioOption {
                        text: "Early: GitHub";
                        checked: root.update-source == "github";
                        selected => {
                            root.update-source = "github";
                            root.update-source-selected("github");
                        }
                    }

                    SettingsRadioOption {
                        text: "Stable: Nexus Mods";
                        checked: root.update-source == "nexus";
                        selected => {
                            root.update-source = "nexus";
                            root.update-source-selected("nexus");
                        }
                    }

                    SettingsRadioOption {
                        text: "Never: Don't Check";
                        checked: root.update-source == "none";
                        selected => {
                            root.update-source = "none";
                            root.update-source-selected("none");
                        }
                    }
                }
            }

            GroupBox {
                title: "Log Level";

                VerticalLayout {
                    padding: 8px;
                    spacing: 8px;
                    alignment: start;

                    SettingsRadioOption {
                        text: "Debug";
                        checked: root.log-level == "debug";
                        selected => {
                            root.log-level = "debug";
                            root.log-level-selected("debug");
                        }
                    }

                    SettingsRadioOption {
                        text: "Info";
                        checked: root.log-level == "info";
                        selected => {
                            root.log-level = "info";
                            root.log-level-selected("info");
                        }
                    }

                    SettingsRadioOption {
                        text: "Warning";
                        checked: root.log-level == "warning";
                        selected => {
                            root.log-level = "warning";
                            root.log-level-selected("warning");
                        }
                    }

                    SettingsRadioOption {
                        text: "Error";
                        checked: root.log-level == "error";
                        selected => {
                            root.log-level = "error";
                            root.log-level-selected("error");
                        }
                    }
                }
            }
        }
    }
}

pub mod app;
pub mod domain;
pub mod platform;
pub mod services;
pub mod workers;

use std::{cell::RefCell, rc::Rc};

use app::settings_controller::SettingsController;
use domain::settings::AppSettings;
use platform::settings_store::{FileAssetResolver, SettingsStore};
use slint::ComponentHandle;

slint::include_modules!();

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let app = MainWindow::new()?;
    let controller = load_settings_controller();

    app.set_update_source(controller.visible_update_source().into());
    app.set_log_level(controller.visible_log_level().into());
    bind_settings_callbacks(&app, controller);

    Ok(app.run()?)
}

fn load_settings_controller() -> SettingsController<FileAssetResolver> {
    SettingsController::load(SettingsStore::production()).unwrap_or_else(|error| {
        tracing::error!(%error, "Settings : Failed to load settings; using in-memory defaults");
        SettingsController::from_settings(SettingsStore::production(), AppSettings::default())
    })
}

fn bind_settings_callbacks(app: &MainWindow, controller: SettingsController<FileAssetResolver>) {
    let controller = Rc::new(RefCell::new(controller));

    app.on_update_source_selected({
        let app = app.as_weak();
        let controller = Rc::clone(&controller);

        move |selected| {
            let visible_value = controller
                .borrow_mut()
                .select_update_source(selected.as_str());
            if let Some(app) = app.upgrade() {
                app.set_update_source(visible_value.into());
            }
        }
    });

    app.on_log_level_selected({
        let app = app.as_weak();
        let controller = Rc::clone(&controller);

        move |selected| {
            let visible_value = controller.borrow_mut().select_log_level(selected.as_str());
            if let Some(app) = app.upgrade() {
                app.set_log_level(visible_value.into());
            }
        }
    });
}

